import type {
  ErrorPayload,
  FullReloadPayload,
  PrunePayload,
  UpdatePayload,
} from './hmrPayload.js'

export interface CustomEventMap {

  'vite:beforeUpdate': UpdatePayload
  'vite:afterUpdate': UpdatePayload
  'vite:beforePrune': PrunePayload
  'vite:beforeFullReload': FullReloadPayload
  'vite:error': ErrorPayload
  'vite:invalidate': InvalidatePayload
  'vite:ws:connect': WebSocketConnectionPayload
  'vite:ws:disconnect': WebSocketConnectionPayload
  /** @internal */
  'vite:forward-console': ForwardConsolePayload
  /** @internal */
  'vite:module-loaded': { modules: string[]; clientId: string }

  'vite:client:connect': undefined
  'vite:client:disconnect': undefined
}

export interface WebSocketConnectionPayload {
  webSocket: WebSocket
}

export interface InvalidatePayload {
  path: string
  message: string | undefined
  firstInvalidatedBy: string
}

export type ForwardConsolePayload =
  | {
      type: 'error'
      data: {
        name: string
        message: string
        stack?: string
      }
    }
  | {
      type: 'unhandled-rejection'
      data: {
        name: string
        message: string
        stack?: string
      }
    }
  | {
      type: 'log'
      data: {
        level: string
        message: string
      }
    }

export type InferCustomEventPayload<T extends string> =
  T extends keyof CustomEventMap ? CustomEventMap[T] : any

export type CustomEventName = keyof CustomEventMap | (string & {})
